sys_script.script:
/**
 * Business Rule: After check-in record is inserted
 * - Looks up reward points from event_venue
 * - Updates points_earned on the checkin record
 * - Creates activity feed entry
 */
(function checkinAfterInsert(current, previous) {
    var eventVenue = new GlideRecord('x_1838075_pub_cr_0_event_venue');
    eventVenue.addQuery('event', current.getValue('event'));
    eventVenue.addQuery('venue', current.getValue('venue'));
    eventVenue.query();

    if (eventVenue.next()) {
        var points = parseInt(eventVenue.getValue('checkin_reward_points'), 10) || 0;

        // Update the current record with points earned
        var checkin = new GlideRecord('x_1838075_pub_cr_0_checkin');
        if (checkin.get(current.getUniqueValue())) {
            checkin.setValue('points_earned', points);
            checkin.update();
        }
    }

    // Create activity feed entry
    var activity = new GlideRecord('x_1838075_pub_cr_0_activity_feed');
    activity.initialize();
    activity.setValue('user', current.getValue('user'));
    activity.setValue('activity_type', 'checkin');
    activity.setValue('venue', current.getValue('venue'));
    activity.setValue('event', current.getValue('event'));
    activity.setValue('message', 'Checked in at a venue');
    activity.insert();
})(current, previous);
